const input = $input.first().json;
const { token, products, tool, marketplace, config } = input.body || input;

// Validate required fields
if (!token) {
  return [{ json: { error: true, code: 'MISSING_TOKEN', message: 'Token is required' } }];
}
if (!products || !Array.isArray(products) || products.length === 0) {
  return [{ json: { error: true, code: 'INVALID_PRODUCTS', message: 'Products array is required and must not be empty' } }];
}
if (!tool) {
  return [{ json: { error: true, code: 'MISSING_TOOL', message: 'tool parameter is required (e.g. xlsx_converter, image_pipeline, offer_mapper)' } }];
}

const validTools = ['xlsx_converter', 'image_pipeline', 'offer_mapper', 'product_enricher', 'ean_validator', 'mirakl_sync', 'full_pipeline'];
if (!validTools.includes(tool)) {
  return [{ json: { error: true, code: 'INVALID_TOOL', message: `Invalid tool '${tool}'. Valid: ${validTools.join(', ')}` } }];
}

const validMarketplaces = ['sprinter', 'mirakl', 'shopify', 'woocommerce', null];
if (marketplace && !validMarketplaces.includes(marketplace)) {
  return [{ json: { error: true, code: 'INVALID_MARKETPLACE', message: `Invalid marketplace '${marketplace}'. Valid: ${validMarketplaces.filter(Boolean).join(', ')}` } }];
}

// Decode JWT
try {
  const parts = token.split('.');
  if (parts.length !== 3) throw new Error('Invalid token format');
  const payload = JSON.parse(Buffer.from(parts[1], 'base64url').toString());

  if (payload.exp && payload.exp < Math.floor(Date.now() / 1000)) {
    return [{ json: { error: true, code: 'TOKEN_EXPIRED', message: 'Token has expired' } }];
  }

  const vendor_id = payload.sub || payload.vendor_id || payload.user_id;
  if (!vendor_id) {
    return [{ json: { error: true, code: 'INVALID_TOKEN', message: 'Token missing subject' } }];
  }

  return [{ json: {
    error: false,
    vendor_id,
    email: payload.email || null,
    products,
    product_count: products.length,
    tool,
    marketplace: marketplace || null,
    config: config || {}
  } }];
} catch (e) {
  return [{ json: { error: true, code: 'AUTH_FAILED', message: 'Token verification failed: ' + e.message } }];
}

const input = $input.first().json;

// Build the job record
const now = new Date().toISOString();
const job = {
  vendor_id: input.vendor_id,
  status: 'queued',
  tool: input.tool,
  marketplace: input.marketplace,
  total_products: input.product_count,
  processed_products: 0,
  error_count: 0,
  input_data: JSON.stringify({
    products: input.products,
    config: input.config,
    tool: input.tool,
    marketplace: input.marketplace
  }),
  result_data: null,
  created_at: now,
  updated_at: now,
  started_at: null,
  completed_at: null
};

return [{ json: { job, vendor_id: input.vendor_id, product_count: input.product_count, tool: input.tool } }];

const response = $input.first().json;
const prevData = $('Prepare Job Record').first().json;

// Supabase returns array with the inserted record
const record = Array.isArray(response) ? response[0] : response;
const job_id = record?.id;

if (!job_id) {
  return [{ json: {
    success: false,
    error: 'job_creation_failed',
    message: 'Failed to create processing job in database',
    details: JSON.stringify(response).substring(0, 500)
  } }];
}

return [{ json: {
  success: true,
  job_id,
  status: 'queued',
  tool: prevData.tool,
  product_count: prevData.product_count,
  message: `Job queued: ${prevData.product_count} products will be processed with ${prevData.tool}`
} }];
